type Signal = { id: string; impact: number }

export function computeRisk(signals: Signal[]) {
  const baseRisk = 28
  const score = signals.reduce((sum, signal) => sum + signal.impact, baseRisk)
  const bounded = Math.max(0, Math.min(100, score))

  return {
    score: bounded,
    verdict: bounded >= 76 ? 'critical' : bounded >= 56 ? 'high' : bounded >= 36 ? 'guarded' : 'low',
    explanation: signals.map((s) => s.id),
  }
}

import { embed } from '@anthropic-ai/embed'

async function captureMemory(userId: string, interaction: Interaction) {
  const embedding = await embed(interaction.summary)

  await supabase.from('living_memory').insert({
    user_id: userId,
    content: interaction.summary,
    embedding,
    context: {
      type: interaction.type, // 'decision' | 'insight' | 'conversation'
      energy_level: interaction.vitals?.energy,
      tags: interaction.extractedTags,
    },
    created_at: new Date().toISOString(),
  })
}

async function recallMemory(userId: string, query: string, limit = 5) {
  const queryEmbedding = await embed(query)

  const { data } = await supabase.rpc('match_memories', {
    query_embedding: queryEmbedding,
    match_user_id: userId, // RLS enforced
    match_count: limit,
    match_threshold: 0.7,
  })

  return data
}

-- Personal Vault: only the owner can read/write
CREATE POLICY personal_vault_owner ON personal_memories
  FOR ALL USING (auth.uid() = user_id);

-- Family Vault: all family members can read, write own
CREATE POLICY family_vault_read ON family_knowledge
  FOR SELECT USING (
    auth.uid() IN (
      SELECT user_id FROM family_memberships
      WHERE family_id = family_knowledge.family_id
    )
  );

CREATE POLICY family_vault_write ON family_knowledge
  FOR INSERT WITH CHECK (auth.uid() = contributed_by);

-- Business Vault: role-based access
CREATE POLICY business_vault_access ON business_intelligence
  FOR ALL USING (
    auth.uid() IN (
      SELECT user_id FROM org_memberships
      WHERE org_id = business_intelligence.org_id
      AND role IN ('admin', 'member')
    )
  );

